	"oa:hasBody": {
		"@type": "oa:TextualBody",
		"dc:format": "text/plain",
		"rdf:value": "Bezieht sich auf das Kabinettformat,  ein Format von Fotografien von ca. 10 × 15 cm, die auf Karton geklebt wurden. Verbreitete sich in der zweiten Hälfte des 19. Jahrhunderts für Portraitaufnahmen. "
